using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public required string DocumentText { get; set; }

    /// <summary>
    /// Maximum number of sentences to include in the summary. Defaults to 3.
    /// </summary>
    [Range(1, 50)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
    public int OriginalLength { get; set; }
    public int SummaryLength { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public partial class DocumentSummarizationService
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a", "an", "the", "and", "or", "but", "is", "are", "was", "were",
        "in", "on", "at", "to", "for", "of", "with", "by", "it", "its",
        "this", "that", "these", "those", "be", "been", "being", "have",
        "has", "had", "do", "does", "did", "will", "would", "could",
        "should", "may", "might", "shall", "can", "not", "no", "so",
        "if", "then", "than", "too", "very", "just", "about", "above",
        "after", "again", "all", "also", "am", "as", "because", "before",
        "between", "both", "each", "from", "further", "he", "her", "here",
        "him", "his", "how", "i", "into", "me", "more", "most", "my",
        "nor", "now", "only", "other", "our", "out", "over", "own",
        "same", "she", "some", "such", "their", "them", "there", "they",
        "through", "under", "up", "we", "what", "when", "where", "which",
        "while", "who", "whom", "why", "you", "your"
    };

    /// <summary>
    /// Produces an extractive summary by scoring sentences based on word frequency
    /// and returning the top-ranked sentences in their original order.
    /// </summary>
    public string Summarize(string documentText, int maxSentences)
    {
        var sentences = SplitIntoSentences(documentText);

        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = ComputeWordFrequencies(sentences);
        var sentenceScores = ScoreSentences(sentences, wordFrequencies);

        var topIndices = sentenceScores
            .Select((score, index) => (score, index))
            .OrderByDescending(x => x.score)
            .Take(maxSentences)
            .Select(x => x.index)
            .OrderBy(i => i); // preserve original order

        var summary = string.Join(" ", topIndices.Select(i => sentences[i]));
        return summary;
    }

    private static List<string> SplitIntoSentences(string text)
    {
        return SentenceBoundary().Matches(text)
            .Select(m => m.Value.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, int> ComputeWordFrequencies(List<string> sentences)
    {
        var frequencies = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in ExtractWords(sentence))
            {
                if (!StopWords.Contains(word) && word.Length > 1)
                {
                    frequencies.TryGetValue(word, out var count);
                    frequencies[word] = count + 1;
                }
            }
        }

        return frequencies;
    }

    private static List<double> ScoreSentences(
        List<string> sentences,
        Dictionary<string, int> wordFrequencies)
    {
        var scores = new List<double>(sentences.Count);

        foreach (var sentence in sentences)
        {
            var words = ExtractWords(sentence);
            if (words.Count == 0)
            {
                scores.Add(0);
                continue;
            }

            double score = words
                .Where(w => wordFrequencies.ContainsKey(w))
                .Sum(w => wordFrequencies[w]);

            // Normalize by sentence length to avoid bias toward long sentences
            scores.Add(score / words.Count);
        }

        return scores;
    }

    private static List<string> ExtractWords(string text)
    {
        return WordPattern().Matches(text)
            .Select(m => m.Value.ToLowerInvariant())
            .ToList();
    }

    [GeneratedRegex(@"[^.!?]*[.!?]+|\s*[^.!?]+$", RegexOptions.Compiled)]
    private static partial Regex SentenceBoundary();

    [GeneratedRegex(@"\b[a-zA-Z']+\b", RegexOptions.Compiled)]
    private static partial Regex WordPattern();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly DocumentSummarizationService _summarizationService;

    public SummarizeController(DocumentSummarizationService summarizationService)
    {
        _summarizationService = summarizationService;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var summary = _summarizationService.Summarize(
            request.DocumentText,
            request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.DocumentText.Length,
            SummaryLength = summary.Length
        });
    }
}

